-- 1. 학생 프로필 테이블 생성 (Profiles table for students)
create table public.profiles (
  id uuid references auth.users not null primary key,
  student_name text not null,
  points integer default 0,
  avatar_url text,
  mypet_url text,
  created_at timestamp with time zone default timezone('utc'::text, now()) not null
);

-- 2. 칭찬 내역 기록 테이블 생성 (Praise notes table)
create table public.praises (
  id bigint generated by default as identity primary key,
  student_id uuid references auth.users not null,
  student_name text not null,
  content text not null,
  points integer not null,
  created_at timestamp with time zone default timezone('utc'::text, now()) not null
);

-- 3. Row Level Security (RLS) 활성화
alter table public.profiles enable row level security;
alter table public.praises enable row level security;

-- 4. RLS 정책 설정 (Security Policies)
-- 모든 사용자(학생, 교사)가 모든 프로필을 조회 가능하도록 설정
create policy "Allow read profiles" on public.profiles for select using (true);

-- 본인의 프로필만 추가/수정 가능하도록 설정
create policy "Allow insert user profile" on public.profiles for insert with check (auth.uid() = id);
create policy "Allow update user profile" on public.profiles for update using (auth.uid() = id);

-- 모든 사용자가 모든 칭찬 기록을 조회 가능하도록 설정
create policy "Allow read praises" on public.praises for select using (true);

-- 본인의 칭찬 기록만 작성 가능하도록 설정
create policy "Allow insert user praises" on public.praises for insert with check (auth.uid() = student_id);
